SELECT p.provider_name
FROM provider_performance pp
JOIN providers p ON pp.provider_id = p.provider_id
WHERE pp.average_download_speed = (
    SELECT MAX(average_download_speed) 
    FROM provider_performance
) AND pp.consumer_satisfaction = (
    SELECT MAX(consumer_satisfaction) 
    FROM provider_performance
);

SELECT SUM(subscription_count) 
FROM consumer_engagement 
WHERE satisfaction_score > 3 AND engagement_date LIKE '2023-%';

SELECT neighborhood_name
FROM neighborhoods
WHERE population > 10000 AND median_home_value < 200000;

SELECT MAX(area_sq_km) AS largest_area
FROM neighborhoods
WHERE population > 1000;
